export const getGetGuildActivityUrl = (guildId: string,
    params?: GetGuildActivityParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : String(value))
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/guilds/${guildId}/activity?${stringifiedParams}` : `/api/guilds/${guildId}/activity`
}

